			ep_curve_get_v2(e);
			ep_curve_get_ord(c);
			bn_rand_mod(a, c);
			BENCH_ADD(bn_rec_glv(a, b, a, c, (const bn_t *)d, (const bn_t *)e));
		}
		BENCH_END;
	}
#endif /* WITH_EP && EP_KBLTZ */

	bn_free(a);
	bn_free(b);
	bn_free(c);
	for (int j = 0; j < 3; j++) {
		bn_free(d[j]);
		bn_free(e[j]);
	}
	crt_free(crt);
}

int main(void) {
	if (core_init() != RLC_OK) {
		core_clean();
		return 1;
	}

	conf_print();
	util_banner("Benchmarks for the BN module:", 0);
	util_banner("Utilities:", 1);
	memory();
	util();
	util_banner("Arithmetic:", 1);
	arith();

	core_clean();
	return 0;
}

